const W = widthMm * mm;
const sheetThickness = 20 * mm;
const ribHeight = 12 * mm;
const ribWidth = 20 * mm;
const ribSpacing = 120 * mm;

const group = new THREE.Group();
const mat = new THREE.MeshLambertMaterial({ color: '#B8C4C8' });
const matRib = new THREE.MeshLambertMaterial({ color: '#C8D4D8' });

// Base sheet
const sheetGeo = new THREE.BoxGeometry(len, W, sheetThickness);
sheetGeo.translate(len / 2, W / 2, sheetThickness / 2);
group.add(new THREE.Mesh(sheetGeo, mat));

// Corrugation ribs, evenly spaced across width
const count = Math.max(1, numRibs);
const margin = (W - count * ribSpacing) / 2 + ribSpacing / 2;
for (let i = 0; i < count; i++) {
  const ribGeo = new THREE.BoxGeometry(len, ribWidth, ribHeight);
  const yPos = margin + i * ribSpacing;
  ribGeo.translate(len / 2, yPos, sheetThickness + ribHeight / 2);
  group.add(new THREE.Mesh(ribGeo, matRib));
}

return group;
